SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS = 0;
SET SQL_MODE = 'NO_AUTO_VALUE_ON_ZERO';

DROP DATABASE IF EXISTS `techparts_co`;
CREATE DATABASE `techparts_co` CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
USE `techparts_co`;

-- ---------------------------------------------------------
-- Tabla: categorias (jerárquica / auto-referenciada)
-- ---------------------------------------------------------
CREATE TABLE `categorias` (
  `categoria_id` INT NOT NULL AUTO_INCREMENT,
  `nombre` VARCHAR(150) NOT NULL,
  `categoria_padre_id` INT DEFAULT NULL,
  PRIMARY KEY (`categoria_id`),
  KEY `idx_categorias_padre` (`categoria_padre_id`),
  CONSTRAINT `fk_categorias_padre` FOREIGN KEY (`categoria_padre_id`)
      REFERENCES `categorias` (`categoria_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- ---------------------------------------------------------
-- Tabla: proveedores
-- ---------------------------------------------------------
CREATE TABLE `proveedores` (
  `proveedor_id` INT NOT NULL AUTO_INCREMENT,
  `nombre` VARCHAR(150) NOT NULL,
  `email` VARCHAR(150) DEFAULT NULL,
  `telefono` VARCHAR(20) DEFAULT NULL,
  `pais` VARCHAR(80) DEFAULT NULL,
  PRIMARY KEY (`proveedor_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- ---------------------------------------------------------
-- Tabla: clientes
-- ---------------------------------------------------------
CREATE TABLE `clientes` (
  `cliente_id` INT NOT NULL AUTO_INCREMENT,
  `nombre` VARCHAR(80) NOT NULL,
  `apellido` VARCHAR(80) NOT NULL,
  `email` VARCHAR(150) NOT NULL,
  `telefono` VARCHAR(20) DEFAULT NULL,
  `direccion` VARCHAR(255) DEFAULT NULL,
  `ciudad` VARCHAR(100) DEFAULT NULL,
  `pais` VARCHAR(80) DEFAULT NULL,
  `fecha_registro` DATETIME NOT NULL,
  PRIMARY KEY (`cliente_id`),
  UNIQUE KEY `uq_clientes_email` (`email`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- ---------------------------------------------------------
-- Tabla: productos (incluye stock_actual y stock_minimo,
-- usados por el Trigger de reabastecimiento de la Parte 3)
-- ---------------------------------------------------------
CREATE TABLE `productos` (
  `producto_id` INT NOT NULL AUTO_INCREMENT,
  `nombre` VARCHAR(150) NOT NULL,
  `descripcion` VARCHAR(255) DEFAULT NULL,
  `categoria_id` INT NOT NULL,
  `proveedor_id` INT NOT NULL,
  `precio` DECIMAL(10,2) NOT NULL,
  `stock_actual` INT NOT NULL DEFAULT 0,
  `stock_minimo` INT NOT NULL DEFAULT 10,
  `fecha_creacion` DATETIME NOT NULL,
  PRIMARY KEY (`producto_id`),
  KEY `idx_productos_categoria` (`categoria_id`),
  KEY `idx_productos_proveedor` (`proveedor_id`),
  CONSTRAINT `fk_productos_categoria` FOREIGN KEY (`categoria_id`) REFERENCES `categorias` (`categoria_id`),
  CONSTRAINT `fk_productos_proveedor` FOREIGN KEY (`proveedor_id`) REFERENCES `proveedores` (`proveedor_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- ---------------------------------------------------------
-- Tabla: pedidos
-- ---------------------------------------------------------
CREATE TABLE `pedidos` (
  `pedido_id` INT NOT NULL AUTO_INCREMENT,
  `cliente_id` INT NOT NULL,
  `fecha_pedido` DATETIME NOT NULL,
  `estado` VARCHAR(20) NOT NULL,
  `direccion_envio` VARCHAR(255) DEFAULT NULL,
  `total` DECIMAL(10,2) NOT NULL DEFAULT 0.00,
  PRIMARY KEY (`pedido_id`),
  KEY `idx_pedidos_cliente` (`cliente_id`),
  CONSTRAINT `fk_pedidos_cliente` FOREIGN KEY (`cliente_id`) REFERENCES `clientes` (`cliente_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- ---------------------------------------------------------
-- Tabla: detalle_pedidos
-- ---------------------------------------------------------
CREATE TABLE `detalle_pedidos` (
  `detalle_id` INT NOT NULL AUTO_INCREMENT,
  `pedido_id` INT NOT NULL,
  `producto_id` INT NOT NULL,
  `cantidad` INT NOT NULL,
  `precio_unitario` DECIMAL(10,2) NOT NULL,
  `subtotal` DECIMAL(10,2) NOT NULL,
  PRIMARY KEY (`detalle_id`),
  KEY `idx_detalle_pedido` (`pedido_id`),
  KEY `idx_detalle_producto` (`producto_id`),
  CONSTRAINT `fk_detalle_pedido` FOREIGN KEY (`pedido_id`) REFERENCES `pedidos` (`pedido_id`),
  CONSTRAINT `fk_detalle_producto` FOREIGN KEY (`producto_id`) REFERENCES `productos` (`producto_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- ---------------------------------------------------------
-- Tabla: logistica_reabastecimiento
-- Destino del Trigger: cuando el stock de un producto cae
-- por debajo de stock_minimo, se debe insertar aquí una
-- orden de reabastecimiento automática.
-- ---------------------------------------------------------
CREATE TABLE `logistica_reabastecimiento` (
  `reabastecimiento_id` INT NOT NULL AUTO_INCREMENT,
  `producto_id` INT NOT NULL,
  `cantidad_solicitada` INT NOT NULL,
  `fecha_solicitud` DATETIME NOT NULL,
  `estado` VARCHAR(20) NOT NULL DEFAULT 'Pendiente',
  `motivo` VARCHAR(255) DEFAULT NULL,
  PRIMARY KEY (`reabastecimiento_id`),
  KEY `idx_logistica_producto` (`producto_id`),
  CONSTRAINT `fk_logistica_producto` FOREIGN KEY (`producto_id`) REFERENCES `productos` (`producto_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

